import { AxisRegistry } from '../../axis-registry';
import { pick  } from '../../../utils/zcutils';

export function getTickGroupPosition(scale1) {
    let _ = this,
        { tickInfo } = _.axisTicks,
        isLevelType = this.axisTicks.tickH.isHierarchialLevelType(),
        attrs = {};
    attrs.position = function(d) {
        let scale = scale1 || _.axisInfo.scale || tickInfo.scale,
            offset = 0;
        if (scale.bandwidth) {
            if (scale.discreteWidth) {
                if (isLevelType) {
                    offset = 0;
                } else {
                    offset = Math.max(0, scale.bandwidth(d) - 1) / 2; // Adjust for 0.5px offset.
                    // if (scale1.round()) {
                    offset = Math.round(offset);
                }
            } else {
                offset = Math.max(0, scale.bandwidth() - 1) / 2; // Adjust for 0.5px offset.
                if (scale.round()) {
                    offset = Math.round(offset);
                }
            }
        }

        var pos = (pick(scale(d), 0)) + (offset || 0);
        return pos;
    };
    attrs.transform = function(d, position) {
        let _position = position || attrs.position(d),
            position2d = _.orient == 'bottom' || _.orient == 'top' ? `${_position + 0.5},0` : `0,${_position + 0.5}`;
        return isNaN(_position) ? null : `translate(${position2d})`;
    };
    return attrs;
}

AxisRegistry.add('cartesian.tickGPosition', getTickGroupPosition);
